#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10,M=2e6+10,dx[4]={0,0,1,-1},dy[4]={1,-1,0,0};int mxn,n,m;
namespace MaxFlow
{
	int s,t,que[N],H,T,dep[N];bool vis[N];
	int head[N],des[N],nxt[N],cap[N],cgt=1;
	inline void ins(int x,int y,int z){nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=z;}
	inline void add(int x,int y,int z){ins(x,y,z);ins(y,x,0);}
	inline int min(int x,int y){return x<y?x:y;}
	inline bool bfs()
	{
		memset(dep+1,0,mxn<<2);dep[que[H=T=1]=s]=1;
		while(H<=T){int u=que[H++];grep(u,i){if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;}}return dep[t];
	}
	inline int dfs(int u=s,int in=0x3f3f3f3f)
	{
		if(u==t)return in;int ou=0;
		grep(u,i)if(cap[i]&&dep[des[i]]==dep[u]+1)
		{
			int tmp=dfs(des[i],cap[i]<in?cap[i]:in);
			cap[i]-=tmp;cap[i^1]+=tmp;in-=tmp;ou+=tmp;if(!in)break;
		}
		if(!ou)dep[u]=0;return ou;
	}
	inline int dinic(int u,int v){s=u;t=v;int ans=0;while(bfs())ans+=dfs();return ans;}
}
using MaxFlow::add;using MaxFlow::dinic;using MaxFlow::head;using MaxFlow::des;using MaxFlow::nxt;using MaxFlow::cap;
char s[1010][1010];bool vis[N],chs[N],loc[N],flag;
inline void dfs(int u,bool typ)
{
	vis[u]=1;if(loc[u]==typ)chs[u]=flag=true;
	grep(u,i)if(!vis[des[i]]&&cap[i]==typ)dfs(des[i],typ);
}
inline int Cnt(int x,int y){return (x-1)*m+y;}
int main()
{
	n=read();m=read();mxn=n*m+2;
	rep(1,n,i)scanf("%s",s[i]+1);
	rep(1,n,i)rep(1,m,j)if(s[i][j]!='#')
	{
		int u=Cnt(i,j);if((i^j)&1)
		{
			loc[u]=1;add(n*m+1,u,1);rep(0,3,d)
			{
				int rx=i+dx[d],ry=j+dy[d];
				if(rx>0&&ry>0&&rx<=n&&ry<=m&&s[rx][ry]!='#')add(u,Cnt(rx,ry),1);
			}
		}else add(u,n*m+2,1);
	}
	
	dinic(n*m+1,n*m+2);dfs(n*m+1,1);memset(vis+1,0,mxn);dfs(n*m+2,0);
	if(!flag){puts("LOSE");return 0;}puts("WIN");
	rep(1,n,i)rep(1,m,j)if(chs[Cnt(i,j)])printf("%d %d\n",i,j);return 0;
}
